// Strip HTML, truncate body, and normalize fields for clean triage input
const item = $input.item.json;

const stripHtml = (html) => {
  if (!html) return '';
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
};

const bodyRaw = item.body?.content || item.bodyPreview || '';
const bodyClean = stripHtml(bodyRaw);

return {
  json: {
    email_id: item.id || '',
    received_date: item.sentDateTime || item.receivedDateTime || '',
    from_address: item.from?.emailAddress?.address || '',
    from_name: item.from?.emailAddress?.name || '',
    to_address: item.toRecipients?.[0]?.emailAddress?.address || '',
    subject: item.subject || '',
    body_preview: bodyClean.substring(0, 500),
    body_full: bodyClean.substring(0, 3000),
    has_attachments: item.hasAttachments ? 'yes' : 'no',
    importance: item.importance || 'normal'
  }
};

