// Merge original email fields with triage output into one flat Excel row
const t = $json.output || {};
const e = $('Normalize Email Fields').item.json;

const safe = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE';
  if (typeof v === 'number') return String(v);
  return String(v).substring(0, 32767); // Excel cell limit
};

return {
  json: {
    email_id:                      safe(e.email_id),
    received_date:                 safe(e.received_date),
    from_address:                  safe(e.from_address),
    from_name:                     safe(e.from_name),
    to_address:                    safe(e.to_address),
    subject:                       safe(e.subject),
    body_preview:                  safe(e.body_preview),
    has_attachments:               safe(e.has_attachments),
    category:                      safe(t.category),
    priority:                      safe(t.priority),
    routing_label:                 safe(t.routing_label),
    is_real_person:                safe(t.is_real_person),
    spam_confidence:               safe(t.spam_confidence),
    requires_keith_decision:       safe(t.requires_keith_decision),
    sensitivity_flag:              safe(t.sensitivity_flag),
