    draft_reply:                   safe(t.draft_reply),
    follow_up_step:                safe(t.follow_up_step),
    confidence_score:              safe(t.confidence_score),
    relationship_type:             safe(t.relationship_type),
    topic_tags:                    safe(t.topic_tags),
    estimated_urgency:             safe(t.estimated_urgency),
    reply_needed:                  safe(t.reply_needed),
    draft_quality_notes:           safe(t.draft_quality_notes),
